"use client";

import {
  type UserNotificationsSetting,
  UserSetting,
  useUpdateUserSettings,
  useUserSettings,
} from "@/entities/profile";
import { Label } from "@/shared/ui/label";
import { Loader } from "@/shared/ui/loader";
import { toast } from "@/shared/ui/notification";
import { Switch } from "@/shared/ui/shadcn/switch";
import { type FC, useCallback, useEffect, useRef } from "react";

export const UserSettings: FC = () => {
  const { data: userSettings, isLoading, isError } = useUserSettings();

  const updateSettingsMutation = useUpdateUserSettings();

  const debounceTimerRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(
    () => () => {
      if (debounceTimerRef.current) {
        clearTimeout(debounceTimerRef.current);
      }
    },
    []
  );

  const handleToggle = useCallback(
    (field: keyof UserNotificationsSetting, value: boolean) => {
      const currentSettings = userSettings?.[UserSetting.Notifications];
      if (!currentSettings) return;

      const updatedNotifications = {
        ...currentSettings,
        [field]: value,
      };

      if (debounceTimerRef.current) {
        clearTimeout(debounceTimerRef.current);
      }

      debounceTimerRef.current = setTimeout(() => {
        updateSettingsMutation.mutate(
          {
            [UserSetting.Notifications]: updatedNotifications,
          },
          {
            onSuccess: () => {
              toast.success("Settings updated");
            },
            onError: () => {
              toast.error("Failed to update settings");
            },
          }
        );
      }, 300);
    },
    [userSettings, updateSettingsMutation]
  );

  const notificationsSettings =
    userSettings?.[UserSetting.Notifications] ?? null;

  if (isLoading) {
    return (
      <div className="flex min-h-[400px] items-center justify-center">
        <Loader />
      </div>
    );
  }

  if (isError || !userSettings || !userSettings[UserSetting.Notifications]) {
    return (
      <div className="flex min-h-[400px] items-center justify-center">
        <p className="font-serif text-foreground">
          Failed to load settings. Please try again.
        </p>
      </div>
    );
  }

  return (
    <div className="new-design flex flex-col gap-6 p-8">
      <h1 className="font-bold font-serif text-[32px] text-foreground leading-[1.199em]">
        Settings
      </h1>

      <div>
        <div className="rounded-[10px] border border-primary px-3 py-4">
          <h2 className="font-bold font-new-serif text-foreground text-lg leading-[1.199em]">
            Notification settings
          </h2>
        </div>
        <div className="mt-3 flex flex-col gap-6 px-6">
          <div className="flex items-center justify-between">
            <div className="flex flex-col gap-1">
              <Label className="font-bold font-serif text-sm">
                General Notification
              </Label>
              <span className="text-sm">
                Enable all Notification for Updates and Alerts
              </span>
            </div>
            <Switch
              checked={notificationsSettings?.general ?? false}
              onCheckedChange={(value) => handleToggle("general", value)}
            />
          </div>

          <div className="flex items-center justify-between">
            <div className="flex flex-col gap-1">
              <Label className="font-bold text-sm">BuyBack Notifications</Label>
              <span className="text-sm">
                Alerts for BuyBack Repayment, due dates etc
              </span>
            </div>
            <Switch
              checked={notificationsSettings?.buyback ?? false}
              onCheckedChange={(value) => handleToggle("buyback", value)}
            />
          </div>

          <div className="flex items-center justify-between">
            <div className="flex flex-col gap-1">
              <Label className="font-bold text-sm">
                Authenticator Notifications
              </Label>
              <span className="text-muted-foreground text-sm">
                Alerts for authentication requests and updates
              </span>
            </div>
            <Switch
              checked={notificationsSettings?.authenticator ?? false}
              onCheckedChange={(value) => handleToggle("authenticator", value)}
            />
          </div>

          <div className="flex items-center justify-between text-[16px]">
            <div className="flex flex-col gap-1">
              <Label className="font-bold text-sm">
                Account Security Alerts
              </Label>
              <span className="text-sm">
                Notifications for login attempts, password changes
              </span>
            </div>
            <Switch
              checked={notificationsSettings?.accountSecurity ?? false}
              onCheckedChange={(value) =>
                handleToggle("accountSecurity", value)
              }
            />
          </div>
        </div>
      </div>
    </div>
  );
};

