import { ApiKeys, TagsEnum } from "@/shared/api/query-keys";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import type {
  UpdateProfileDto,
  UpdateProfilePhotoDto,
  UpdateSettingsDto,
  UpsertAddressDto,
  UserSettings,
} from "../model/types";
import * as profileService from "./services";

export function useProfile() {
  return useQuery({
    queryKey: ApiKeys.profile(),
    queryFn: profileService.getProfile,
  });
}

export function useAddresses() {
  return useQuery({
    queryKey: ApiKeys.address(),
    queryFn: profileService.getAddresses,
    retry: false,
  });
}

export function useUpdateProfile() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (data: UpdateProfileDto) => profileService.updateProfile(data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ApiKeys.profile() });
    },
  });
}

export function useUpdateProfilePhoto() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (data: UpdateProfilePhotoDto) =>
      profileService.updateProfilePhoto(data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ApiKeys.profile() });
    },
  });
}

export function useUpsertAddress() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (data: UpsertAddressDto) => profileService.upsertAddress(data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ApiKeys.address() });
    },
  });
}

export function useDeleteAddress() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (id: string) => profileService.deleteAddress(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ApiKeys.address() });
    },
  });
}

export function useUserSettings() {
  return useQuery({
    queryKey: ApiKeys.userSettings(),
    queryFn: profileService.getUserSettings,
    retry: false,
  });
}

export function useUpdateUserSettings() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (data: UpdateSettingsDto) =>
      profileService.updateUserSettings(data),
    onMutate: async (newSettings) => {
      const queryKey = ApiKeys.userSettings();

      await queryClient.cancelQueries({ queryKey });

      const previousSettings = queryClient.getQueryData<UserSettings>(queryKey);

      queryClient.setQueryData<UserSettings>(queryKey, (old) => {
        if (!old) return old;

        return {
          ...old,
          ...newSettings,
        };
      });

      return { previousSettings };
    },
    onError: (_error, _variables, context) => {
      if (context?.previousSettings) {
        queryClient.setQueryData(
          ApiKeys.userSettings(),
          context.previousSettings,
        );
      }
    },
    onSettled: () => {
      queryClient.invalidateQueries({
        queryKey: [TagsEnum.USER_SETTINGS],
      });
    },
  });
}

